void generarVariaciones(int m, int n) {
    vector<char> combinacion(n);
    backtrack(combinacion, m, n, 0);
}

void backtrack(vector<char>& combinacion, int m, int n, int nivel) {
    if (nivel == n) {
        // Imprimir la combinación actual
        return;
    }
    for (int i = 0; i < m; ++i) {
        combinacion[nivel] = 'a' + i;
        backtrack(combinacion, m, n, nivel + 1);
    }
}
